'use client';

/**
 * Calculadora de Precificação
 */

import { useState, useMemo } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Separator } from '@/components/ui/separator';
import { Badge } from '@/components/ui/badge';
import { Slider } from '@/components/ui/slider';
import {
    Calculator,
    TrendingUp,
    Bot,
    Code,
    Star,
    Target,
    Crown,
    ArrowLeft
} from 'lucide-react';
import Link from 'next/link';

interface ServiceState {
    googleAdsEnabled: boolean;
    googleAdsInvestment: number;
    googleAdsFixedValue: number;
    metaAdsEnabled: boolean;
    metaAdsFixedValue: number;
    metaAdsInvestment: number;
    landingPageEnabled: boolean;
    landingPageValue: number;
    automationEnabled: boolean;
    automationAgentCount: number;
    saasEnabled: boolean;
    saasPeriod: string;
    applyDiscount: boolean;
    discountPercent: number;
}

export default function PricingCalculatorPage() {
    const [services, setServices] = useState<ServiceState>({
        googleAdsEnabled: false,
        googleAdsInvestment: 0,
        googleAdsFixedValue: 1500,
        metaAdsEnabled: false,
        metaAdsFixedValue: 1000,
        metaAdsInvestment: 0,
        landingPageEnabled: false,
        landingPageValue: 1500,
        automationEnabled: false,
        automationAgentCount: 0,
        saasEnabled: false,
        saasPeriod: '7-14',
        applyDiscount: false,
        discountPercent: 30,
    });

    const updateService = (updates: Partial<ServiceState>) => {
        setServices(prev => ({ ...prev, ...updates }));
    };

    const calculations = useMemo(() => {
        let marketingTotal = 0;
        let automationTotal = 0;
        let saasTotal = 0;
        let clientInvestmentTotal = 0;

        // Marketing - Google Ads
        if (services.googleAdsEnabled) {
            clientInvestmentTotal += services.googleAdsInvestment;
            marketingTotal += services.googleAdsFixedValue;
        }

        // Marketing - Meta Ads
        if (services.metaAdsEnabled) {
            clientInvestmentTotal += services.metaAdsInvestment;
            marketingTotal += services.metaAdsFixedValue;
        }

        // Marketing - Landing Page
        if (services.landingPageEnabled) {
            marketingTotal += services.landingPageValue;
        }

        // Automação IA
        if (services.automationEnabled && services.automationAgentCount > 0) {
            automationTotal += 2000; // Taxa de implementação
            automationTotal += services.automationAgentCount * 1500; // R$ 1.500 por agente
        }

        // SaaS
        if (services.saasEnabled) {
            const saasPrices: Record<string, number> = {
                '7-14': 1200,
                '15-30': 2400,
                '31-60': 4800,
                '61-120': 9600
            };
            saasTotal += saasPrices[services.saasPeriod] || 0;
        }

        let total = marketingTotal + automationTotal + saasTotal;

        // Apply discount
        if (services.applyDiscount) {
            total *= (100 - services.discountPercent) / 100;
        }

        const totalWithInvestment = total + clientInvestmentTotal;

        return {
            marketing: marketingTotal,
            automation: automationTotal,
            saas: saasTotal,
            clientInvestment: clientInvestmentTotal,
            total,
            totalWithInvestment,
        };
    }, [services]);

    const formatCurrency = (value: number) => {
        return value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
    };

    return (
        <div className="min-h-screen space-y-8 bg-background pb-20">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Link href="/calculators">
                    <Button variant="ghost" size="icon">
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                </Link>
                <div className="bg-gradient-to-br from-primary via-primary to-primary/90 rounded-xl p-6 text-white shadow-lg flex-1">
                    <div className="flex items-center gap-4">
                        <Calculator className="w-10 h-10" />
                        <div>
                            <h1 className="text-2xl font-bold">Calculadora de Precificação</h1>
                            <p className="text-white/90">Monte propostas personalizadas</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Serviços - Coluna esquerda */}
                <div className="lg:col-span-2 space-y-6">
                    {/* Marketing */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <TrendingUp className="w-5 h-5 text-primary" />
                                Marketing Digital
                            </CardTitle>
                            <CardDescription>Gestão de tráfego e campanhas</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            {/* Google Ads */}
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <Label htmlFor="google-ads" className="text-base font-medium">Google Ads</Label>
                                    <Switch
                                        id="google-ads"
                                        checked={services.googleAdsEnabled}
                                        onCheckedChange={(checked) => updateService({ googleAdsEnabled: checked })}
                                    />
                                </div>

                                {services.googleAdsEnabled && (
                                    <div className="space-y-4 pl-4 border-l-2 border-primary/20">
                                        <div className="space-y-2">
                                            <Label>Investimento do Cliente (R$)</Label>
                                            <Input
                                                type="number"
                                                value={services.googleAdsInvestment}
                                                onChange={(e) => updateService({ googleAdsInvestment: Number(e.target.value) })}
                                                placeholder="Ex: 5000"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Valor da Gestão (R$)</Label>
                                            <Input
                                                type="number"
                                                value={services.googleAdsFixedValue}
                                                onChange={(e) => updateService({ googleAdsFixedValue: Number(e.target.value) })}
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>

                            <Separator />

                            {/* Meta Ads */}
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <Label htmlFor="meta-ads" className="text-base font-medium">Meta Ads</Label>
                                    <Switch
                                        id="meta-ads"
                                        checked={services.metaAdsEnabled}
                                        onCheckedChange={(checked) => updateService({ metaAdsEnabled: checked })}
                                    />
                                </div>

                                {services.metaAdsEnabled && (
                                    <div className="space-y-4 pl-4 border-l-2 border-primary/20">
                                        <div className="space-y-2">
                                            <Label>Valor Fixo (R$)</Label>
                                            <Input
                                                type="number"
                                                value={services.metaAdsFixedValue}
                                                onChange={(e) => updateService({ metaAdsFixedValue: Number(e.target.value) })}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Investimento do Cliente (R$)</Label>
                                            <Input
                                                type="number"
                                                value={services.metaAdsInvestment}
                                                onChange={(e) => updateService({ metaAdsInvestment: Number(e.target.value) })}
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>

                            <Separator />

                            {/* Landing Page */}
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <Label htmlFor="landing-page" className="text-base font-medium">Landing Page</Label>
                                    <Switch
                                        id="landing-page"
                                        checked={services.landingPageEnabled}
                                        onCheckedChange={(checked) => updateService({ landingPageEnabled: checked })}
                                    />
                                </div>

                                {services.landingPageEnabled && (
                                    <div className="space-y-4 pl-4 border-l-2 border-primary/20">
                                        <div className="space-y-2">
                                            <Label>Valor: {formatCurrency(services.landingPageValue)}</Label>
                                            <Slider
                                                value={[services.landingPageValue]}
                                                onValueChange={([value]) => updateService({ landingPageValue: value })}
                                                max={2000}
                                                min={1500}
                                                step={50}
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Automação por IA */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Bot className="w-5 h-5 text-primary" />
                                Automação por I.A.
                            </CardTitle>
                            <CardDescription>Agentes inteligentes</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <div className="flex items-center justify-between">
                                <Label htmlFor="automation" className="text-base font-medium">Ativar Automação</Label>
                                <Switch
                                    id="automation"
                                    checked={services.automationEnabled}
                                    onCheckedChange={(checked) => updateService({ automationEnabled: checked })}
                                />
                            </div>

                            {services.automationEnabled && (
                                <div className="space-y-4 pl-4 border-l-2 border-primary/20">
                                    <Badge variant="outline">Taxa de implementação: R$ 2.000</Badge>
                                    <div className="space-y-2">
                                        <Label>Número de Agentes (R$ 1.500 cada)</Label>
                                        <Input
                                            type="number"
                                            min="0"
                                            max="6"
                                            value={services.automationAgentCount}
                                            onChange={(e) => updateService({ automationAgentCount: Number(e.target.value) })}
                                        />
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* SaaS */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Code className="w-5 h-5 text-primary" />
                                SaaS e MicroSaaS
                            </CardTitle>
                            <CardDescription>Desenvolvimento personalizado</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <div className="flex items-center justify-between">
                                <Label htmlFor="saas" className="text-base font-medium">Incluir SaaS</Label>
                                <Switch
                                    id="saas"
                                    checked={services.saasEnabled}
                                    onCheckedChange={(checked) => updateService({ saasEnabled: checked })}
                                />
                            </div>

                            {services.saasEnabled && (
                                <div className="space-y-4 pl-4 border-l-2 border-primary/20">
                                    <div className="space-y-3">
                                        <Label>Prazo de desenvolvimento:</Label>
                                        {[
                                            { key: '7-14', label: '7 a 14 dias', price: 'R$ 1.200' },
                                            { key: '15-30', label: '15 a 30 dias', price: 'R$ 2.400' },
                                            { key: '31-60', label: '31 a 60 dias', price: 'R$ 4.800' },
                                            { key: '61-120', label: '61 a 120 dias', price: 'R$ 9.600' }
                                        ].map(({ key, label, price }) => (
                                            <div key={key} className="flex items-center space-x-2">
                                                <input
                                                    type="radio"
                                                    id={key}
                                                    name="saasPeriod"
                                                    checked={services.saasPeriod === key}
                                                    onChange={() => updateService({ saasPeriod: key })}
                                                    className="w-4 h-4 text-primary"
                                                />
                                                <Label htmlFor={key}>{label} - {price}</Label>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>

                {/* Resumo - Coluna direita */}
                <div className="space-y-6">
                    {/* Resumo de Custos */}
                    <Card className="sticky top-4">
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Target className="w-5 h-5 text-primary" />
                                Resumo de Custos
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-3">
                                <div className="flex justify-between">
                                    <span>Marketing:</span>
                                    <span className="font-medium">{formatCurrency(calculations.marketing)}</span>
                                </div>
                                {calculations.clientInvestment > 0 && (
                                    <div className="flex justify-between text-sm text-muted-foreground">
                                        <span>+ Investimento do Cliente:</span>
                                        <span>{formatCurrency(calculations.clientInvestment)}</span>
                                    </div>
                                )}
                                <div className="flex justify-between">
                                    <span>Automação IA:</span>
                                    <span className="font-medium">{formatCurrency(calculations.automation)}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span>SaaS:</span>
                                    <span className="font-medium">{formatCurrency(calculations.saas)}</span>
                                </div>
                                <Separator />

                                {/* Discount */}
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <Label htmlFor="discount" className="text-sm font-medium">
                                            Aplicar desconto
                                        </Label>
                                        <Switch
                                            id="discount"
                                            checked={services.applyDiscount}
                                            onCheckedChange={(checked) => updateService({ applyDiscount: checked })}
                                        />
                                    </div>
                                    {services.applyDiscount && (
                                        <div className="space-y-2">
                                            <Label>Desconto: {services.discountPercent}%</Label>
                                            <Slider
                                                value={[services.discountPercent]}
                                                onValueChange={([value]) => updateService({ discountPercent: value })}
                                                max={50}
                                                min={10}
                                                step={5}
                                            />
                                        </div>
                                    )}
                                </div>

                                <Separator />

                                <div className="flex justify-between text-base font-semibold">
                                    <span>Subtotal (Serviços):</span>
                                    <span>{formatCurrency(calculations.total)}</span>
                                </div>
                                {calculations.clientInvestment > 0 && (
                                    <div className="flex justify-between text-lg font-bold text-primary">
                                        <span>Total com Investimento:</span>
                                        <span>{formatCurrency(calculations.totalWithInvestment)}</span>
                                    </div>
                                )}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Proposta Final */}
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Crown className="w-5 h-5 text-primary" />
                                Proposta Final
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="p-4 rounded-lg bg-gradient-to-br from-primary via-primary to-primary/90 text-white">
                                <div className="flex items-center gap-2 mb-2">
                                    <Star className="w-4 h-4" />
                                    <span className="font-bold">Valor Total</span>
                                </div>
                                <div className="text-3xl font-bold">
                                    {formatCurrency(calculations.totalWithInvestment)}
                                </div>
                                {services.applyDiscount && (
                                    <p className="text-sm text-white/80 mt-2">
                                        Inclui desconto de {services.discountPercent}%
                                    </p>
                                )}
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}
